#include<bits/stdc++.h>
using namespace std;
long long a[1005], b[1005];
int n,k;
int cou(double x) {
	priority_queue<double> p;
	for (int i = 1; i <= n; i++) {
		p.push((double)a[i] - (double)b[i]*x);
	}
	double sum = 0;
	for (int i = 1; i <= n-k; i++) {
		sum += p.top();
		//cout << p.top( )<<"   d\n";
		p.pop();
	}
	//cout<<sum<<"   e  \n";
	if (sum >= 0) return 2;
	else return 0;    
}
void solve() {
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++) cin>>b[i];
	double l = 0, r = 1,mid;
	for(int i=1;i<=2500;i++){
		mid = (l + r) / 2;
		//cout<<mid<<"\n";
		//for(int i=1;i<=1000000000;i++) ;
		int ans=cou(mid);
        if(ans==0){
			r=mid;
		}else{
			l=mid;
		}
	}
    cout<<(long long)((l)*100+0.5)<<"\n";
	return;
}
int main(){
	while(1){
		cin>>n>>k;
		if(n==0&&k==0) break;
		solve();
	}
	return 0;
}
